proof fn phi_1_range_consistent_vacuous_equal_iterators<K: KeyTrait + VerusClone>(dm: DelegationMap<K>, k: K, id: ID)
    ensures
        dm.range_consistent(&KeyIterator::new_spec(k), &KeyIterator::new_spec(k), &id),
{
    K::cmp_properties();
    dm.empty_key_range_is_consistent(&KeyIterator::new_spec(k), &KeyIterator::new_spec(k), &id);
}

proof fn phi_2_empty_range_any_endpoint<K: KeyTrait + VerusClone>(dm: DelegationMap<K>, id1: ID, id2: ID, k: K)
    ensures
        dm.range_consistent(&KeyIterator::new_spec(k), &KeyIterator::new_spec(k), &id1),
        dm.range_consistent(&KeyIterator::new_spec(k), &KeyIterator::new_spec(k), &id2),
{
    K::cmp_properties();
    dm.empty_key_range_is_consistent(&KeyIterator::new_spec(k), &KeyIterator::new_spec(k), &id1);
    dm.empty_key_range_is_consistent(&KeyIterator::new_spec(k), &KeyIterator::new_spec(k), &id2);
}

proof fn phi_3_end_iterator_geq_everything<K: KeyTrait + VerusClone>(dm: DelegationMap<K>, ki: KeyIterator<K>, id: ID)
    requires
        ki.k.is_None(),
    ensures
        dm.range_consistent(&ki, &KeyIterator::new_spec(K::zero_spec()), &id),
{
    K::cmp_properties();
    dm.empty_key_range_is_consistent(&ki, &KeyIterator::new_spec(K::zero_spec()), &id);
}

proof fn phi_5_range_consistent_contradicts_map_value<K: KeyTrait + VerusClone>(dm: DelegationMap<K>, lo: K, hi: K, k: K, id: ID)
    requires
        lo.cmp_spec(k).lt(),
        k.cmp_spec(hi).lt(),
        dm@[k] != id@,
        lo.cmp_spec(hi).lt(),
    ensures
        !dm.range_consistent(&KeyIterator::new_spec(lo), &KeyIterator::new_spec(hi), &id),
{
    K::cmp_properties();
    assert(KeyIterator::between(KeyIterator::new_spec(lo), KeyIterator::new_spec(k), KeyIterator::new_spec(hi)));
}
